import { ethers } from 'ethers';
import DeChat from '../contracts/DeChat.json';

// ============================================
// CONTRACT CONFIGURATION
// ============================================

/**
 * Deployed contract address on Sepolia testnet
 * Replace this with your actual deployed contract address
 */
const CONTRACT_ADDRESS = "0x416A0A3839Bcbee98Cf2D5F0f089369648b7B736";

/**
 * Sepolia testnet chain ID
 */
const SEPOLIA_CHAIN_ID = '0xaa36a7'; // 11155111 in decimal

// ============================================
// CORE CONTRACT FUNCTIONS
// ============================================

/**
 * Get contract instance connected with signer (for write operations)
 * 
 * @returns {Promise<ethers.Contract>} Contract instance with signer
 * @throws {Error} If MetaMask is not installed or user not connected
 * 
 * @example
 * const contract = await getContract();
 * const tx = await contract.createRoom("General", false);
 */
export const getContract = async () => {
  try {
    // Check if MetaMask is installed
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask is not installed. Please install MetaMask to use this app.');
    }

    // Create provider from MetaMask
    const provider = new ethers.BrowserProvider(window.ethereum);

    // Request account access if needed
    await provider.send('eth_requestAccounts', []);

    // Get the signer (connected wallet)
    const signer = await provider.getSigner();

    // Create contract instance with signer
    const contract = new ethers.Contract(
      CONTRACT_ADDRESS,
      DeChat.abi,
      signer
    );

    console.log('✅ Contract connected:', CONTRACT_ADDRESS);
    console.log('👤 Connected wallet:', await signer.getAddress());

    return contract;
  } catch (error) {
    console.error('Failed to get contract:', error);
    throw error;
  }
};

/**
 * Get contract instance for read-only operations (no signer)
 * 
 * @returns {Promise<ethers.Contract>} Contract instance with provider
 * @throws {Error} If MetaMask is not installed
 * 
 * @example
 * const contract = await getContractReadOnly();
 * const rooms = await contract.getAllRooms();
 */
export const getContractReadOnly = async () => {
  try {
    // Check if MetaMask is installed
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask is not installed. Please install MetaMask to use this app.');
    }

    // Create provider from MetaMask
    const provider = new ethers.BrowserProvider(window.ethereum);

    // Create contract instance with provider only (read-only)
    const contract = new ethers.Contract(
      CONTRACT_ADDRESS,
      DeChat.abi,
      provider
    );

    console.log('✅ Contract connected (read-only):', CONTRACT_ADDRESS);

    return contract;
  } catch (error) {
    console.error('Failed to get contract (read-only):', error);
    throw error;
  }
};

// ============================================
// NETWORK HELPERS
// ============================================

/**
 * Check if user is on Sepolia network
 * 
 * @returns {Promise<boolean>} True if on Sepolia
 */
export const isSepoliaNetwork = async () => {
  try {
    if (typeof window.ethereum === 'undefined') {
      return false;
    }

    const provider = new ethers.BrowserProvider(window.ethereum);
    const network = await provider.getNetwork();
    
    // Compare chain ID (Sepolia is 11155111)
    return network.chainId === 11155111n;
  } catch (error) {
    console.error('Failed to check network:', error);
    return false;
  }
};

/**
 * Switch to Sepolia network
 * 
 * @returns {Promise<boolean>} True if successful
 */
export const switchToSepolia = async () => {
  try {
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask is not installed');
    }

    await window.ethereum.request({
      method: 'wallet_switchEthereumChain',
      params: [{ chainId: SEPOLIA_CHAIN_ID }],
    });

    console.log('✅ Switched to Sepolia network');
    return true;
  } catch (error) {
    // This error code indicates that the chain has not been added to MetaMask
    if (error.code === 4902) {
      try {
        await window.ethereum.request({
          method: 'wallet_addEthereumChain',
          params: [
            {
              chainId: SEPOLIA_CHAIN_ID,
              chainName: 'Sepolia Testnet',
              nativeCurrency: {
                name: 'ETH',
                symbol: 'ETH',
                decimals: 18,
              },
              rpcUrls: ['https://rpc.sepolia.org'],
              blockExplorerUrls: ['https://sepolia.etherscan.io'],
            },
          ],
        });
        console.log('✅ Sepolia network added and switched');
        return true;
      } catch (addError) {
        console.error('Failed to add Sepolia network:', addError);
        return false;
      }
    }
    console.error('Failed to switch network:', error);
    return false;
  }
};

// ============================================
// CONTRACT INFO
// ============================================

/**
 * Get contract address
 * 
 * @returns {string} Contract address
 */
export const getContractAddress = () => {
  return CONTRACT_ADDRESS;
};

/**
 * Validate contract address is set
 * 
 * @returns {boolean} True if contract address is configured
 */
export const isContractConfigured = () => {
  return CONTRACT_ADDRESS !== "PASTE_MY_DEPLOYED_CONTRACT_ADDRESS";
};

// ============================================
// HELPER FUNCTIONS FOR COMMON CONTRACT CALLS
// ============================================

/**
 * Create a new chat room
 * 
 * @param {string} name - Room name
 * @param {boolean} isPrivate - Whether room is private
 * @returns {Promise<Object>} Transaction receipt with roomId
 */
export const createRoom = async (name, isPrivate) => {
  const contract = await getContract();
  const tx = await contract.createRoom(name, isPrivate);
  const receipt = await tx.wait();
  
  console.log('✅ Room created, tx hash:', receipt.hash);
  return receipt;
};

/**
 * Send message to room
 * 
 * @param {number} roomId - Room ID
 * @param {string} content - Message content
 * @returns {Promise<Object>} Transaction receipt
 */
export const sendMessage = async (roomId, content) => {
  const contract = await getContract();
  const tx = await contract.sendMessage(roomId, content);
  const receipt = await tx.wait();
  
  console.log('✅ Message sent:', receipt.hash);
  return receipt;
};

/**
 * Mint NFT
 * 
 * @param {string} name - NFT name
 * @param {string} metadataURI - Metadata URI
 * @returns {Promise<Object>} Transaction receipt
 */
export const mintNFT = async (name, metadataURI) => {
  const contract = await getContract();
  const tx = await contract.mintNFT(name, metadataURI);
  const receipt = await tx.wait();
  
  console.log('✅ NFT minted:', receipt.hash);
  return receipt;
};

/**
 * Buy NFT
 * 
 * @param {number} tokenId - NFT token ID
 * @param {string} price - Price in wei
 * @returns {Promise<Object>} Transaction receipt
 */
export const buyNFT = async (tokenId, price) => {
  const contract = await getContract();
  const tx = await contract.buyNFT(tokenId, { value: price });
  const receipt = await tx.wait();
  
  console.log('✅ NFT purchased:', receipt.hash);
  return receipt;
};

/**
 * Get all chat rooms
 * 
 * @returns {Promise<Array>} Array of room objects
 */
export const getAllRooms = async () => {
  const contract = await getContractReadOnly();
  const rooms = await contract.getAllRooms();
  
  return rooms.map(room => ({
    id: room.id.toString(),
    name: room.name,
    creator: room.creator,
    isPrivate: room.isPrivate,
    createdAt: room.createdAt.toString(),
    exists: room.exists
  }));
};

/**
 * Get all listed NFTs
 * 
 * @returns {Promise<Array>} Array of NFT objects
 */
export const getAllListedNFTs = async () => {
  const contract = await getContractReadOnly();
  const nfts = await contract.getAllListedNFTs();
  
  return nfts.map(nft => ({
    tokenId: nft.tokenId.toString(),
    owner: nft.owner,
    name: nft.name,
    metadataURI: nft.metadataURI,
    price: nft.price.toString(),
    isListed: nft.isListed
